export function createBossmannWohnungPackage(id: string, title: string, defaultArea: number, defaultFloorCount: number): RenovationPackage {
  const rows = WOHNUNG_ROWS[id] ?? WOHNUNG_ROWS['2zi'];
  const grouped = new Map<string, WohnungRow[]>();
  rows.forEach((row) => {
    const category = row[0];
    grouped.set(category, [...(grouped.get(category) ?? []), row]);
  });

  return {
    id,
    title,
    defaultArea,
    defaultFloorCount,
    categories: Array.from(grouped, ([categoryTitle, categoryRows], categoryIndex) => {
      const meta = CATEGORY_META[categoryTitle] ?? CATEGORY_META['Weitere Positionen'];
      const sectionRows = new Map<ProductSeed['type'], WohnungRow[]>();
      categoryRows.forEach((row) => {
        const type = row[5];
        sectionRows.set(type, [...(sectionRows.get(type) ?? []), row]);
      });

      return {
        id: meta.id,
        title: categoryTitle,
        lead: meta.lead,
        collapsedByDefault: categoryIndex > 0,
        subsections: Array.from(sectionRows, ([type, typedRows]) => {
          const sectionId = type === 'service' ? 'execution' : type === 'material' ? 'material' : type === 'extra' ? 'extras' : 'optional';
          const sectionTitle = type === 'service' ? 'Art der Ausfuehrung' : type === 'material' ? 'Material' : type === 'extra' ? 'Extra Positionen' : 'Optionale Positionen';
          return {
            id: sectionId,
            title: sectionTitle,
            type,
            products: typedRows.map((row) => {
              const [, name, price, unit, baseQuantity, , sku, enabled] = row;
              const seed: ProductSeed = {
                id: sku.toLowerCase(),
                title: name,
                sku,
                type,
                unit,
                basePrice: price,
                baseQuantity,
                enabled,
                optional: type === 'optional',
              };
              return createProduct(meta.id, sectionId, seed);
            }),
          };
        }),
      };
    }),
  };
}
